function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    const replaced: boolean[] = new Array(n).fill(false);
    const prefix: number[] = new Array(n + 1).fill(0);

    // Precompute the number of '*' in the string at each step
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + (replaced[i] ? 1 : 0);
    }

    // Function to calculate the number of valid substrings
    function countValidSubstrings() {
        let total = 0;
        for (let i = 0; i < n; i++) {
            for (let j = i; j < n; j++) {
                if (prefix[j + 1] - prefix[i] > 0) {
                    total++;
                }
            }
        }
        return total;
    }

    // Binary search for the minimum time t
    let left = 0, right = n;
    let answer = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        // Replace the first mid elements in order
        for (let i = 0; i < mid; i++) {
            const idx = order[i];
            replaced[idx] = true;
        }

        const count = countValidSubstrings();
        if (count >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }

        // Reset the replaced array for the next iteration
        for (let i = 0; i < mid; i++) {
            const idx = order[i];
            replaced[idx] = false;
        }
    }

    return answer;
}

